// Per-CA phase overrides stored here
var CA_OVERRIDES={};

function getCAPhases(caId,baseProgress){
  var phases=Object.keys(WBS_HIERARCHY);
  var overrides=(CA_OVERRIDES[caId])||{};
  return phases.map(function(ph,i){
    var data=WBS_HIERARCHY[ph];
    var allTasks=data.activities.reduce(function(acc,a){return acc.concat(a.tasks);},[]);
    var totalTasks=allTasks.length;
    var pct;
    if(typeof overrides[i]==='number'){
      pct=overrides[i];
    } else {
      var threshold=(i/17)*100;
      pct=baseProgress>=threshold+6?100:baseProgress>=threshold?Math.round((baseProgress-threshold)/6*100):0;
      pct=Math.min(100,Math.max(0,pct));
    }
    var doneTasks=Math.round(pct/100*totalTasks);
    return {
      name:ph,code:data.code,pct:pct,
      totalTasks:totalTasks,doneTasks:doneTasks,
      activities:data.activities,
      cls:pct>=100?'ph-done':pct>0?'ph-wip':'ph-todo'
    };
  });
}

function setCAPhasePct(caId,phaseIdx,pct){
  if(!CA_OVERRIDES[caId])CA_OVERRIDES[caId]={};
  CA_OVERRIDES[caId][phaseIdx]=parseInt(pct);
  // Refresh the detail view
  var ca=COMMON_AREAS.find(function(c){return c.id===caId;});
  if(ca)openCommonAreaDetail(ca);
}

function openCommonAreaDetail(ca){
  document.body.classList.remove('no-project');
  currentView='ca_detail';
  var phases=getCAPhases(ca.id,ca.progress);
  var totalTasks=phases.reduce(function(s,p){return s+p.totalTasks;},0);
  var doneTasks=phases.reduce(function(s,p){return s+p.doneTasks;},0);
  var overallPct=totalTasks>0?Math.round(doneTasks/totalTasks*100):0;
  var barColor=overallPct>=80?'#2e7d32':overallPct>=50?'#e65100':'#757575';
  var statusLabel=ca.status==='done'?'Completed':ca.status==='wip'?'In Progress':'Not Started';
  var statusColor=ca.status==='done'?'#2e7d32':ca.status==='wip'?'#e65100':'#757575';

  var phaseHtml=phases.map(function(ph,i){
    var actHtml=ph.activities.map(function(act){
      var taskHtml=act.tasks.map(function(t,ti){
        var done=Math.round(ph.pct/100*act.tasks.length)>ti;
        return '<div class="ca-task-row">'
          +'<span class="phase-task-dot" style="background:'+(done?'#2e7d32':'#9e9e9e')+'"></span>'
          +'<span class="ca-task-wbs">'+ph.code+'.'+act.code.split('.').slice(-1)[0]+'.'+(ti+1)+'</span>'
          +'<span class="ca-task-name">'+t+'</span>'
          +'<span class="ca-task-status" style="color:'+(done?'#2e7d32':'#9e9e9e')+'">'+(done?'Done':'Pending')+'</span>'
        +'</div>';
      }).join('');
      return '<div class="ca-activity">'
        +'<div class="ca-activity-hdr">'+act.code+' '+act.name+' <span style="margin-left:auto;font-size:11px;color:#9ca3af">'+act.tasks.length+' tasks</span></div>'
        +taskHtml
      +'</div>';
    }).join('');

    return '<div class="phase-card '+ph.cls+'" id="caphc-'+i+'">'
      +'<div class="phase-card-hdr" onclick="toggleCAPhaseFn('+i+')">'
        +'<span class="phase-card-name">'+ph.name+'</span>'
        +'<span class="phase-card-count">'+ph.doneTasks+'/'+ph.totalTasks+' Completed ('+ph.pct+'%)</span>'
        +'<span class="phase-card-menu" onclick="event.stopPropagation()">&#8942;</span>'
        +'<span class="phase-card-chev" id="caphchev-'+i+'">&#8964;</span>'
      +'</div>'
      +'<div class="phase-card-body" id="caphb-'+i+'">'
        +'<div style="display:flex;align-items:center;gap:8px;padding:8px 0 12px;border-bottom:1px solid #f3f4f6;margin-bottom:8px">'
          +'<span style="font-size:12px;color:#374151;font-weight:500">Phase Progress:</span>'
          +'<input type="range" min="0" max="100" value="'+ph.pct+'" '
          +'data-caid="'+ca.id+'" data-phidx="'+i+'" '
          +'style="flex:1;cursor:pointer;accent-color:'+barColor+'" '
          +'oninput="this.nextElementSibling.textContent=this.value+\'%\';this.style.accentColor=this.value>=100?\'#2e7d32\':this.value>0?\'#e65100\':\'#757575\'" '
          +'onchange="setCAPhasePct(this.dataset.caid,this.dataset.phidx,this.value)">'
          +'<span style="font-size:12px;font-weight:600;color:'+barColor+';min-width:36px">'+ph.pct+'%</span>'
        +'</div>'
        +actHtml
      +'</div>'
    +'</div>';
  }).join('');

  var content=renderProjectHeader()
    +'<div class="unit-detail-wrap">'
      +'<div class="unit-detail-hdr">'
        +'<span class="unit-detail-back" onclick="switchView(\'units_view\')">'
          +'<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><polyline points="15 18 9 12 15 6"/></svg>'
          +' '+ca.icon+' '+ca.name
        +'</span>'
        +'<span class="unit-detail-menu" onclick="showToast(\'options\',\'info\')">&#8942;</span>'
      +'</div>'
      +'<div class="unit-info-box" style="margin-bottom:16px">'
        +'<div class="unit-info-row">'
          +'<div class="unit-info-cell"><b>Construction Status:</b><span style="color:'+statusColor+'">&#9679; '+statusLabel+'</span></div>'
          +'<div class="unit-info-cell"><b>Category:</b>'+ca.category+'</div>'
        +'</div>'
        +'<div class="unit-info-row">'
          +'<div class="unit-info-cell"><b>Tasks Complete:</b>'+doneTasks+' / '+totalTasks+'</div>'
          +'<div class="unit-info-cell"><b>Overall Progress:</b><span style="color:'+barColor+';font-weight:600">'+overallPct+'%</span></div>'
        +'</div>'
        +'<div style="padding:12px 16px">'
          +'<div style="height:8px;background:#f3f4f6;border-radius:4px;overflow:hidden">'
            +'<div style="height:100%;width:'+overallPct+'%;background:'+barColor+';border-radius:4px;transition:width .3s"></div>'
          +'</div>'
        +'</div>'
      +'</div>'
      +'<div class="unit-section-title">Construction Phases & Subtasks</div>'
      +phaseHtml
    +'</div>';

  document.getElementById('view-title').textContent=ca.name;
  document.getElementById('view-breadcrumb').textContent='Common Area · '+ca.category;
  document.querySelector('.content').innerHTML=content;
  document.querySelector('.content').scrollTop=0;
  renderRoleNav(currentRole);
}

function toggleCAPhaseFn(i){
  var b=document.getElementById('caphb-'+i),c=document.getElementById('caphchev-'+i);
  if(!b)return;
  var open=b.classList.toggle('open');
  if(c)c.style.transform=open?'rotate(180deg)':'';
}

