function getCommonAreaPhases(area){
  var base=area.progress||0;
  return CA_WBS_PHASES.map(function(ph,i){
    var tasks=CA_PHASE_TASKS[ph]||["Work"];
    var total=tasks.length;
    var th=(i/17)*100;
    var pct=base>=th+6?100:base>=th?Math.round((base-th)/6*100):0;
    pct=Math.min(100,Math.max(0,pct));
    var done=Math.round(pct/100*total);
    return{name:ph,tasks:tasks,done:done,total:total,pct:pct,
      color:pct>=100?"#2e7d32":pct>0?"#e65100":"#9e9e9e",
      cls:pct>=100?"ph-done":pct>0?"ph-wip":"ph-todo"};
  });
}
